using System.Windows.Forms;

class MainForm : Form
{
    private StatusStrip _statusStrip;
    private ToolStripStatusLabel _statusLabel;

    public MainForm()
    {
        _statusLabel = new ToolStripStatusLabel("Ready");

        _statusStrip = new StatusStrip();
        // .NET 9 changed the StatusStrip default RenderMode from System to
        // ManagerRenderMode. Set it explicitly to preserve the .NET 8 look.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        _statusStrip.Items.Add(_statusLabel);

        Controls.Add(_statusStrip);
    }

    public void SetStatus(string text)
    {
        _statusLabel.Text = text;
    }
}

using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

class PropertyEditor : UITypeEditor
{
    public override object? EditValue(
        System.ComponentModel.ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null)
            return value;

        var control = BuildEditorControl(value);

        // .NET 9 throws ArgumentNullException when null is passed to
        // DropDownControl. Guard against it so callers that previously
        // relied on a silent no-op still behave correctly.
        if (control != null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    public override UITypeEditorEditStyle GetEditStyle(
        System.ComponentModel.ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    private static Control? BuildEditorControl(object? currentValue)
    {
        if (currentValue is not string text)
            return null;

        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { "Option A", "Option B", "Option C" });
        listBox.SelectedItem = text;
        return listBox;
    }

    private static object? GetValueFromControl(Control control)
    {
        if (control is ListBox listBox)
            return listBox.SelectedItem;
        return null;
    }
}

